/*
Thank you to Niall - (https://codepen.io/niallains/pen/ExEOmdJ)
This Tartan Plaid Generator is based on the original work by Niall. Thank you for sharing your creative code and inspiring this project!
*/

const BASE_COLORS = [
	"#000000",
	"#d3d3d3",
	"#5f9ea0",
	"#000080",
	"#008080",
	"#6495ed",
	"#40e0d0",
	"#808000",
	"#ffd700",
	"#800000",
	"#ff8c00",
	"#dc143c",
	"#a52a2a",
	"#006400",
	"#228b22",
	"#20b2aa",
	"#800080",
	"#c71585",
	"#d8bfd8"
];
let selectedColors = [...BASE_COLORS.slice(0, 6)];
let currentLines = [];
let currentBgColor = selectedColors[0];
let paletteCollapsed = !1;
let currentSeed = Math.floor(Math.random() * 10000);
let dragSrcEl = null;
let isDragging = !1;
const patternTiles = [];
const PATTERN_WIDTH = 25;
let BASE = 6;
let currentColor = {
	h: 0,
	s: 100,
	b: 100
};
let isMouseDown = !1;
let activeElement = null;

function togglePalette() {
	const controls = document.getElementById("controls");
	const toggleBtn = document.getElementById("toggleBtn");
	paletteCollapsed = !paletteCollapsed;
	controls.classList.toggle("collapsed", paletteCollapsed);
	toggleBtn.textContent = paletteCollapsed ? "▶" : "◀";
	updateHelpButtonPosition();
}

function updateHelpButtonPosition() {
	const helpBtn = document.getElementById("helpBtn");
	const controls = document.getElementById("controls");
	const controlsRect = controls.getBoundingClientRect();
	if (paletteCollapsed) {
		helpBtn.style.left =
			controlsRect.left + controlsRect.width * 0.15 + 20 + "px";
	} else {
		helpBtn.style.left = controlsRect.right + 20 + "px";
	}
}

function openHelpModal() {
	const modal = document.getElementById("helpModal");
	modal.classList.add("active");
}

function closeHelpModal() {
	const modal = document.getElementById("helpModal");
	modal.classList.remove("active");
}

function scrollToLanguage(lang) {
	const element = document.getElementById("lang-" + lang);
	if (element) {
		const content = document.getElementById("helpContent");
		content.scrollTo({
			top: element.offsetTop - content.offsetTop - 20,
			behavior: "smooth"
		});
		document.querySelectorAll(".flag-btn").forEach((btn) => {
			btn.classList.remove("active");
		});
		event.target.classList.add("active");
	}
}

function initColorPalette() {
	const palette = document.getElementById("colorPalette");
	const selectedContainer = document.getElementById("selectedColors");
	palette.innerHTML = "";
	selectedContainer.innerHTML = "";
	selectedColors.forEach((color) => {
		const colorOption = createColorOption(color, !0);
		selectedContainer.appendChild(colorOption);
	});
	BASE_COLORS.forEach((color) => {
		if (!selectedColors.includes(color)) {
			const colorOption = createColorOption(color, !1);
			palette.appendChild(colorOption);
		}
	});
}

function createColorOption(color, isSelected) {
	const colorOption = document.createElement("div");
	colorOption.className = "color-option";
	colorOption.style.backgroundColor = color;
	colorOption.dataset.color = color;
	colorOption.draggable = isSelected;
	if (isSelected) {
		colorOption.classList.add("selected");
		colorOption.addEventListener("dragstart", handleDragStart);
		colorOption.addEventListener("dragover", handleDragOver);
		colorOption.addEventListener("dragenter", handleDragEnter);
		colorOption.addEventListener("dragleave", handleDragLeave);
		colorOption.addEventListener("drop", handleDrop);
		colorOption.addEventListener("dragend", handleDragEnd);
	}
	colorOption.onclick = (e) => {
		if (isDragging) {
			isDragging = !1;
			return;
		}
		if (isSelected) {
			const index = selectedColors.indexOf(color);
			if (index > -1) {
				selectedColors.splice(index, 1);
			}
		} else {
			selectedColors.push(color);
		}
		initColorPalette();
		generatePatternWithCurrentSeed();
	};
	return colorOption;
}

function handleDragStart(e) {
	if (e.target.className.includes("color-option")) {
		dragSrcEl = e.target;
		isDragging = !0;
		e.target.classList.add("dragging");
		e.dataTransfer.effectAllowed = "move";
		e.dataTransfer.setData("text/html", e.target.outerHTML);
	}
}

function handleDragOver(e) {
	if (e.preventDefault) {
		e.preventDefault();
	}
	e.dataTransfer.dropEffect = "move";
	return !1;
}

function handleDragEnter(e) {
	if (e.target.className.includes("color-option") && e.target !== dragSrcEl) {
		e.target.classList.add("drop-target");
	}
}

function handleDragLeave(e) {
	if (e.target.className.includes("color-option")) {
		e.target.classList.remove("drop-target");
	}
}

function handleDrop(e) {
	e.stopPropagation();
	e.preventDefault();
	if (
		dragSrcEl &&
		dragSrcEl !== e.target &&
		e.target.className.includes("color-option")
	) {
		e.target.classList.remove("drop-target");
		const draggedColor = dragSrcEl.dataset.color;
		const targetColor = e.target.dataset.color;
		const draggedIndex = selectedColors.indexOf(draggedColor);
		const targetIndex = selectedColors.indexOf(targetColor);
		if (draggedIndex > -1 && targetIndex > -1) {
			[selectedColors[draggedIndex], selectedColors[targetIndex]] = [
				selectedColors[targetIndex],
				selectedColors[draggedIndex]
			];
			initColorPalette();
			generatePatternWithCurrentSeed();
		}
	}
	return !1;
}

function handleDragEnd(e) {
	if (dragSrcEl) {
		dragSrcEl.classList.remove("dragging");
		document.querySelectorAll(".color-option.drop-target").forEach((el) => {
			el.classList.remove("drop-target");
		});
		dragSrcEl = null;
	}
}

function initColorPicker() {
	const pickerButton = document.getElementById("picker-button");
	const colorPicker = document.getElementById("colorPicker");
	const colorSquare = document.querySelector(".color-square");
	const hueBar = document.querySelector(".hue-bar");
	const colorSelector = document.querySelector(".color-selector-outer");
	const hueSelector = document.querySelector(".hue-selector");
	const addColorBtn = document.getElementById("addColorBtn");
	pickerButton.style.backgroundColor = hsbToHex(currentColor);
	pickerButton.addEventListener("click", function (e) {
		const rect = this.getBoundingClientRect();
		colorPicker.style.left = rect.left + window.scrollX + "px";
		colorPicker.style.top = rect.top + rect.height + 10 + window.scrollY + "px";
		colorPicker.style.display = "block";
		e.stopPropagation();
	});
	document.addEventListener("click", function (e) {
		if (!colorPicker.contains(e.target) && e.target !== pickerButton) {
			colorPicker.style.display = "none";
		}
	});
	colorPicker.addEventListener("click", function (e) {
		e.stopPropagation();
	});
	colorSquare.addEventListener("mousedown", function (e) {
		isMouseDown = !0;
		activeElement = "color";
		updateColorFromSquare(e);
	});
	hueBar.addEventListener("mousedown", function (e) {
		isMouseDown = !0;
		activeElement = "hue";
		updateHue(e);
	});
	document.addEventListener("mousemove", function (e) {
		if (!isMouseDown) return;
		if (activeElement === "color") {
			updateColorFromSquare(e);
		} else if (activeElement === "hue") {
			updateHue(e);
		}
	});
	document.addEventListener("mouseup", function () {
		isMouseDown = !1;
		activeElement = null;
	});
	addColorBtn.addEventListener("click", function () {
		const hexColor = hsbToHex(currentColor);
		addColorFromPicker(hexColor);
	});

	function updateColorFromSquare(e) {
		const rect = colorSquare.getBoundingClientRect();
		const width = rect.width;
		const height = rect.height;
		const x = Math.max(0, Math.min(e.clientX - rect.left, width));
		const y = Math.max(0, Math.min(e.clientY - rect.top, height));
		currentColor.s = Math.round((x / width) * 100);
		currentColor.b = 100 - Math.round((y / height) * 100);
		updateUI();
	}

	function updateHue(e) {
		const rect = hueBar.getBoundingClientRect();
		const height = rect.height;
		const y = Math.max(0, Math.min(e.clientY - rect.top, height));
		currentColor.h = Math.round((1 - y / height) * 360);
		updateUI();
	}

	function updateUI() {
		const squareRect = colorSquare.getBoundingClientRect();
		const squareWidth = squareRect.width;
		const squareHeight = squareRect.height;
		const selectorX = (currentColor.s / 100) * squareWidth;
		const selectorY = ((100 - currentColor.b) / 100) * squareHeight;
		colorSelector.style.left = selectorX + "px";
		colorSelector.style.top = selectorY + "px";
		const hueRect = hueBar.getBoundingClientRect();
		const hueHeight = hueRect.height;
		const hueY = ((360 - currentColor.h) / 360) * hueHeight;
		hueSelector.style.top = hueY + "px";
		const hueColor = hsbToHex({
			h: currentColor.h,
			s: 100,
			b: 100
		});
		colorSquare.style.backgroundColor = hueColor;
		const hexColor = hsbToHex(currentColor);
		pickerButton.style.backgroundColor = hexColor;
	}
}

function hsbToHex(hsb) {
	const rgb = hsbToRgb(hsb);
	return rgbToHex(rgb);
}

function hsbToRgb(hsb) {
	const h = hsb.h / 360;
	const s = hsb.s / 100;
	const b = hsb.b / 100;
	const i = Math.floor(h * 6);
	const f = h * 6 - i;
	const p = b * (1 - s);
	const q = b * (1 - f * s);
	const t = b * (1 - (1 - f) * s);
	let r, g, bVal;
	switch (i % 6) {
		case 0:
			r = b;
			g = t;
			bVal = p;
			break;
		case 1:
			r = q;
			g = b;
			bVal = p;
			break;
		case 2:
			r = p;
			g = b;
			bVal = t;
			break;
		case 3:
			r = p;
			g = q;
			bVal = b;
			break;
		case 4:
			r = t;
			g = p;
			bVal = b;
			break;
		case 5:
			r = b;
			g = p;
			bVal = q;
			break;
		default:
			r = 0;
			g = 0;
			bVal = 0;
	}
	return {
		r: Math.round(r * 255),
		g: Math.round(g * 255),
		b: Math.round(bVal * 255)
	};
}

function rgbToHex(rgb) {
	return (
		"#" + componentToHex(rgb.r) + componentToHex(rgb.g) + componentToHex(rgb.b)
	);
}

function componentToHex(c) {
	const hex = c.toString(16);
	return hex.length === 1 ? "0" + hex : hex;
}

function addColorFromPicker(color) {
	if (!BASE_COLORS.includes(color) && !selectedColors.includes(color)) {
		BASE_COLORS.push(color);
		selectedColors.push(color);
		initColorPalette();
		generatePatternWithCurrentSeed();
	}
	document.getElementById("colorPicker").style.display = "none";
}

function getLine(vert, color, offset) {
	const OFF_X = vert ? offset * BASE : BASE / 2,
		OFF_Y = vert ? 0 : offset * BASE;
	return `linear-gradient(
          45deg,
          ${color} 0 ${BASE / 3}px,
          transparent ${BASE / 3}px ${BASE * (2 / 3)}px,
          ${color} ${BASE * (2 / 3)}px ${BASE}px,
          transparent ${BASE + 1}px
        ) ${OFF_X}px ${OFF_Y}px /
        ${BASE}px ${BASE}px repeat-${vert ? "y" : "x"}`;
}

function getPattern(lines, bg) {
	const WIDTH = (PATTERN_WIDTH - 1) * 2;
	let css = "";
	lines.forEach((l) => {
		for (let pos = l[1]; pos < l[1] + l[2]; pos++) {
			const mixedColor = `color-mix(in srgb, ${l[0]} 75%, ${bg} 25%)`;
			css +=
				getLine(!1, l[0], pos) +
				", " +
				getLine(!0, mixedColor, pos) +
				", " +
				getLine(!1, l[0], WIDTH - pos) +
				", " +
				getLine(!0, l[0], WIDTH - pos) +
				", ";
		}
	});
	return css + bg;
}

function generatePatternWithCurrentSeed() {
	stopAnimation();
	BASE = parseInt(document.getElementById("lineWidth").value);
	const patternDensity = parseInt(
		document.getElementById("patternDensity").value
	);
	const RNG = [0x80000000, 1103515245, 12345, currentSeed];
	const randInt = (max) => {
		RNG[3] = (RNG[1] * RNG[3] + RNG[2]) % RNG[0];
		return Math.floor((max * RNG[3]) / RNG[0]);
	};
	const randEl = (arr) => arr[randInt(arr.length)];
	let lines = [];
	let pos = 4 + randInt(6);
	while (pos < PATTERN_WIDTH) {
		let lineWidthActual = randInt(4);
		if (pos + lineWidthActual > PATTERN_WIDTH) {
			lineWidthActual = PATTERN_WIDTH - pos;
		}
		const shouldAddLine = randInt(10) < patternDensity;
		if (shouldAddLine) {
			lines.push([randEl(selectedColors), pos, lineWidthActual]);
		}
		pos += lineWidthActual;
	}
	currentLines = lines;
	currentBgColor = randEl(selectedColors);
	const pattern = getPattern(lines, currentBgColor);
	const EL_WIDTH = BASE * PATTERN_WIDTH * 2;
	patternTiles.forEach((tile) => {
		tile.style.width = EL_WIDTH + "px";
		tile.style.height = EL_WIDTH + "px";
		tile.style.background = pattern;
	});
	resizePatternContainer();
}

function generateRandomPattern() {
	stopAnimation();
	currentSeed = Math.floor(Math.random() * 10000);
	generatePatternWithCurrentSeed();
}

function resetPattern() {
	selectedColors = [...BASE_COLORS.slice(0, 6)];
	document.getElementById("lineWidth").value = 6;
	document.getElementById("lineWidthValue").textContent = "6";
	document.getElementById("patternDensity").value = 5;
	document.getElementById("densityValue").textContent = "5";
	currentColor = {
		h: 0,
		s: 100,
		b: 100
	};
	document.getElementById("picker-button").style.backgroundColor = hsbToHex(
		currentColor
	);
	currentSeed = Math.floor(Math.random() * 10000);
	initColorPalette();
	generatePatternWithCurrentSeed();
}
let ani;

function startAnimation() {
	clearInterval(ani);
	ani = setInterval(() => {
		generateRandomPattern();
	}, 400);
}

function stopAnimation() {
	clearInterval(ani);
}

function updateSliderValues() {
	document.getElementById(
		"lineWidthValue"
	).textContent = document.getElementById("lineWidth").value;
	document.getElementById("densityValue").textContent = document.getElementById(
		"patternDensity"
	).value;
	generatePatternWithCurrentSeed();
}

function resizePatternContainer() {
	const EL_WIDTH = BASE * PATTERN_WIDTH * 2;
	const container = document.getElementById("patternContainer");
	const viewportWidth = window.innerWidth;
	const viewportHeight = window.innerHeight;
	const tilesX = Math.ceil(viewportWidth / EL_WIDTH) + 2;
	const tilesY = Math.ceil(viewportHeight / EL_WIDTH) + 2;
	const neededTiles = tilesX * tilesY;
	if (patternTiles.length < neededTiles) {
		for (let i = patternTiles.length; i < neededTiles; i++) {
			const tile = document.createElement("div");
			tile.className = "pattern-tile";
			tile.style.width = EL_WIDTH + "px";
			tile.style.height = EL_WIDTH + "px";
			tile.style.background = getPattern(currentLines, currentBgColor);
			container.appendChild(tile);
			patternTiles.push(tile);
		}
	} else if (patternTiles.length > neededTiles) {
		while (patternTiles.length > neededTiles) {
			const tile = patternTiles.pop();
			if (tile && tile.parentNode) {
				tile.parentNode.removeChild(tile);
			}
		}
	}
	container.style.width = tilesX * EL_WIDTH + "px";
	container.style.height = tilesY * EL_WIDTH + "px";
}

function initPage() {
	document
		.getElementById("lineWidth")
		.addEventListener("input", updateSliderValues);
	document
		.getElementById("patternDensity")
		.addEventListener("input", updateSliderValues);
	document.getElementById("toggleBtn").addEventListener("click", togglePalette);
	document.getElementById("helpBtn").addEventListener("click", openHelpModal);
	window.addEventListener("resize", () => {
		resizePatternContainer();
		updateHelpButtonPosition();
	});
	initColorPicker();
	document.getElementById("helpModal").addEventListener("click", (e) => {
		if (e.target.id === "helpModal") {
			closeHelpModal();
		}
	});
	document.addEventListener("keydown", (e) => {
		if (
			e.key === "Escape" &&
			document.getElementById("helpModal").classList.contains("active")
		) {
			closeHelpModal();
		}
	});
	initColorPalette();
	generatePatternWithCurrentSeed();
	updateHelpButtonPosition();
}
initPage();

style.css:
html,
body {
	overflow: hidden;
	margin: 0;
	padding: 0;
	width: 100%;
	height: 100%;
}

#patternContainer {
	position: absolute;
	top: 0;
	left: 0;
	width: 100%;
	height: 100%;
	display: flex;
	flex-wrap: wrap;
	transform-origin: 0 0;
}

.pattern-tile {
	flex-shrink: 0;
}

.controls {
	position: fixed;
	top: 20px;
	left: 20px;
	z-index: 100;
	background: rgb(255 255 255 / 0.95);
	padding: 15px;
	border-radius: 8px;
	box-shadow: 0 4px 12px rgb(0 0 0 / 0.15);
	max-width: 320px;
	transition: transform 0.3s ease, opacity 0.3s ease;
}

.controls.collapsed {
	transform: translateX(-108%);
	opacity: 0.7;
}

.toggle-btn {
	position: absolute;
	top: 10px;
	right: -30px;
	width: 30px;
	height: 30px;
	background: rgb(255 255 255 / 0.95);
	border: none;
	border-radius: 0 4px 4px 0;
	cursor: pointer;
	display: flex;
	align-items: center;
	justify-content: center;
	font-size: 16px;
	box-shadow: 2px 0 4px rgb(0 0 0 / 0.1);
	color: #000;
}

.toggle-btn:hover {
	background: #fff;
}

.color-palette-section {
	margin-bottom: 15px;
}

.section-title {
	font-size: 12px;
	font-weight: 700;
	color: #333;
	margin-bottom: 8px;
	display: block;
}

.color-palette {
	display: grid;
	grid-template-columns: repeat(6, 1fr);
	gap: 6px;
	margin-bottom: 10px;
}

.selected-colors-container {
	position: relative;
	margin-bottom: 15px;
	padding-bottom: 15px;
}

.selected-colors-container::after {
	content: "";
	position: absolute;
	bottom: 0;
	left: 0;
	right: 0;
	height: 1px;
	background: linear-gradient(to right, transparent, #ccc, transparent);
}

.selected-colors-title {
	font-size: 12px;
	font-weight: 700;
	color: #333;
	margin-bottom: 8px;
	display: block;
}

.selected-colors {
	display: grid;
	grid-template-columns: repeat(6, 1fr);
	gap: 6px;
	margin-bottom: 10px;
	min-height: 28px;
}

.color-option {
	width: 28px;
	height: 28px;
	border-radius: 4px;
	border: 2px solid #fff0;
	cursor: pointer;
	transition: transform 0.2s, border-color 0.2s;
	position: relative;
}

.color-option:hover {
	transform: scale(1.1);
}

.color-option.selected {
	border-color: #333;
	transform: scale(1.1);
}

.color-option.dragging {
	opacity: 0.7;
	z-index: 1000;
	transform: scale(1.15);
	box-shadow: 0 4px 12px rgb(0 0 0 / 0.2);
}

.color-option.drop-target {
	border-color: #4a6fa5;
	border-style: dashed;
}

.controls.collapsed .color-palette-section,
.controls.collapsed .slider-container,
.controls.collapsed .pattern-controls {
	opacity: 0;
	pointer-events: none;
}

.color-picker-row {
	display: flex;
	align-items: center;
	gap: 10px;
	margin-top: 8px;
}

#picker-button {
	display: inline-block;
	background-color: #4a6fa5;
	border: 2px solid #afafaf;
	box-shadow: 1px 1px 4px #000;
	border-radius: 40px;
	padding: 0;
	margin: 0;
	width: 28px;
	height: 28px;
	vertical-align: bottom;
	cursor: pointer;
	flex-shrink: 0;
}

.add-color-btn {
	flex: 1;
	padding: 6px 10px;
	border: none;
	border-radius: 4px;
	background: #4a6fa5;
	color: #fff;
	cursor: pointer;
	font-size: 11px;
	transition: background 0.2s;
}

.add-color-btn:hover {
	background: #3a5a8a;
}

.slider-container {
	margin: 12px 0;
	transition: opacity 0.3s ease;
}

.slider-with-value {
	display: flex;
	align-items: center;
	gap: 10px;
	margin-top: 5px;
}

.slider-value {
	font-size: 11px;
	color: #666;
	min-width: 30px;
	text-align: right;
}

label {
	display: block;
	margin-bottom: 5px;
	font-size: 12px;
	font-weight: 700;
	color: #333;
}

input[type="range"] {
	flex: 1;
	height: 6px;
	margin: 0;
	-webkit-appearance: none;
	background: #e0e0e0;
	border-radius: 3px;
	outline: none;
}

input[type="range"]::-webkit-slider-thumb {
	-webkit-appearance: none;
	width: 16px;
	height: 16px;
	border-radius: 50%;
	background: #4a6fa5;
	cursor: pointer;
}

input[type="range"]::-moz-range-thumb {
	width: 16px;
	height: 16px;
	border-radius: 50%;
	background: #4a6fa5;
	cursor: pointer;
	border: none;
}

.pattern-controls {
	display: grid;
	grid-template-columns: 1fr 1fr;
	gap: 8px;
	margin-top: 15px;
	transition: opacity 0.3s ease;
}

button {
	padding: 8px 12px;
	border: none;
	border-radius: 4px;
	background: #4a6fa5;
	color: #fff;
	cursor: pointer;
	font-size: 12px;
	transition: background 0.2s;
}

span {
	position: fixed;
	z-index: 10;
	bottom: 10px;
	right: 10px;
	color: #fff;
	font-size: 14px;
	text-align: right;
}

#densityValue,
#lineWidthValue {
	display: none;
}

a {
	color: #fff;
}

.color-picker {
	position: fixed;
	display: none;
	font-family: Arial, Helvetica, sans-serif;
	background: #ebebeb;
	border: 1px solid #bbb;
	border-radius: 5px;
	user-select: none;
	padding: 10px;
	box-shadow: 0 4px 12px rgb(0 0 0 / 0.3);
	z-index: 1001;
}

.color-square {
	position: relative;
	width: 156px;
	height: 156px;
	overflow: hidden;
	outline: 1px solid #aaa;
	cursor: crosshair;
	float: left;
}

.color-overlay1,
.color-overlay2 {
	position: absolute;
	left: 0;
	top: 0;
	width: 100%;
	height: 100%;
	pointer-events: none;
}

.color-overlay1 {
	background: linear-gradient(to right, white 0%, #fff0 100%);
}

.color-overlay2 {
	background: linear-gradient(to bottom, #fff0 0%, black 100%);
}

.color-selector-outer {
	position: absolute;
	width: 11px;
	height: 11px;
	margin: -6px 0 0 -6px;
	border: 1px solid #000;
	border-radius: 50%;
	pointer-events: none;
	z-index: 10;
}

.color-selector-inner {
	position: absolute;
	width: 9px;
	height: 9px;
	border: 1px solid #fff;
	border-radius: 50%;
	pointer-events: none;
}

.hue-bar {
	position: relative;
	width: 20px;
	height: 156px;
	border: 1px solid #aaa;
	cursor: ns-resize;
	float: left;
	margin-left: 10px;
	background: linear-gradient(
		to bottom,
		#ff0000 0%,
		#ff0080 8.33%,
		#ff00ff 16.67%,
		#8000ff 25%,
		#0000ff 33.33%,
		#0080ff 41.67%,
		#00ffff 50%,
		#00ff80 58.33%,
		#00ff00 66.67%,
		#80ff00 75%,
		#ffff00 83.33%,
		#ff8000 91.67%,
		#ff0000 100%
	);
}

.hue-selector {
	position: absolute;
	width: 100%;
	height: 7px;
	margin: -3.5px 0 0 0;
	pointer-events: none;
	left: 0;
	z-index: 10;
}

.hue-arrow-left,
.hue-arrow-right {
	position: absolute;
	width: 0;
	height: 0;
	border-top: 6px solid #fff0;
	border-bottom: 6px solid #fff0;
}

.hue-arrow-left {
	left: -7px;
	border-left: 7px solid #858585;
}

.hue-arrow-right {
	right: -7px;
	border-right: 7px solid #858585;
}

.clearfix:after {
	content: "";
	display: table;
	clear: both;
}

.help-btn {
	position: fixed;
	bottom: 26px;
	left: inherit !important;
	right: 26px;
	z-index: 101;
	width: 36px;
	height: 36px;
	background: rgb(255 255 255 / 0.95);
	border: none;
	border-radius: 50%;
	cursor: pointer;
	display: flex;
	align-items: center;
	justify-content: center;
	font-size: 18px;
	font-weight: 700;
	color: #4a6fa5;
	box-shadow: 0 2px 8px rgb(0 0 0 / 0.15);
	transition: all 0.3s ease;
}

.help-btn:hover {
	background: #fff;
	transform: scale(1.1);
	box-shadow: 0 4px 12px rgb(0 0 0 / 0.2);
}

.controls.collapsed ~ .help-btn {
	left: calc(15% + 20px);
}

.help-modal {
	display: none;
	position: fixed;
	top: 0;
	left: 0;
	width: 100%;
	height: 100%;
	background: rgb(0 0 0 / 0.5);
	z-index: 2000;
	justify-content: center;
	align-items: center;
}

.help-modal.active {
	display: flex;
}

.help-modal-container {
	background: #fff;
	border-radius: 12px;
	padding: 0;
	box-shadow: 0 8px 32px rgb(0 0 0 / 0.2);
	width: 600px;
	max-width: 90vw;
	max-height: 80vh;
	display: flex;
	flex-direction: column;
}

.help-modal-header {
	position: sticky;
	top: 0;
	background: #fff;
	z-index: 10;
	padding: 20px 20px 15px 20px;
	border-bottom: 1px solid #eee;
	border-radius: 12px 12px 0 0;
}

.help-modal-title-container {
	display: flex;
	justify-content: space-between;
	align-items: center;
	margin-bottom: 12px;
}

.help-modal-title {
	font-weight: 700;
	color: #333;
	font-size: 18px;
}

.help-modal-close {
	position: absolute;
	right: 20px;
	background: none;
	border: none;
	font-size: 24px;
	cursor: pointer;
	color: #666;
	padding: 0;
	width: 30px;
	height: 30px;
	display: flex;
	align-items: center;
	justify-content: right;
}

.help-modal-close:hover {
	color: red;
	transform: scale(1.2);
	transition: all 0.8s ease-in-out;
}

.language-flags {
	display: flex;
	gap: 8px;
	flex-wrap: wrap;
	margin-top: 5px;
}

.flag-btn {
	background: none;
	border: 1px solid #ddd;
	border-radius: 4px;
	padding: 4px 8px;
	font-size: 14px;
	cursor: pointer;
	transition: all 0.2s;
	color: #333;
	min-width: 40px;
	text-align: center;
}

.flag-btn:hover {
	background: #f0f0f0;
	border-color: #4a6fa5;
	transform: scale(1.05);
}

.flag-btn.active {
	background: #4a6fa5;
	color: #fff;
	border-color: #4a6fa5;
}

.help-content {
	padding: 0 20px 20px 20px;
	overflow-y: auto;
	flex-grow: 1;
}

.language-section {
	margin-bottom: 30px;
}

.language-title {
	font-weight: 700;
	color: #4a6fa5;
	font-size: 16px;
	margin-bottom: 10px;
	padding-bottom: 5px;
	border-bottom: 2px solid #e0e0e0;
}

.instruction-list {
	margin: 0;
	padding-left: 20px;
}

.instruction-list li {
	margin-bottom: 8px;
	font-size: 14px;
	color: #333;
}

.instruction-list strong {
	color: #4a6fa5;
}

.note {
	margin-top: 20px;
	padding: 10px 15px;
	background: #f0f7ff;
	border-left: 4px solid #4a6fa5;
	border-radius: 4px;
	font-size: 13px;
	color: #555;
}

.note strong {
	color: #4a6fa5;
}

.language-separator {
	height: 2px;
	background: linear-gradient(to right, transparent, #ccc, transparent);
	margin: 25px 0;
}

.rtl {
	direction: rtl;
	text-align: right;
}

.rtl .instruction-list {
	padding-right: 20px;
	padding-left: 0;
}

.rtl .note {
	border-left: none;
	border-right: 4px solid #4a6fa5;
}

.copy {
	position: fixed;
	top: 20px;
	right: 20px;
	color: #000;
	background: rgb(255 255 255 / 0.7);
	padding: 10px;
	border-radius: 5px;
	font-size: 12px;
	pointer-events: none;
}
